        if ((i >= 0) && (str.charAt(i) == '.')) {
            i++;
            continue;
        }
        if ((i + 2 < n) && (str.substring(i, i + 3).equals("xyz"))) {
            return true;
        }
        i++;
    }
    return false;
}

