public int[] zeroMax(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 0) {
            int maxOdd = findMaxOdd(nums, i + 1);
            if (maxOdd != -1) {
                nums[i] = maxOdd;
            }
        }
    }
    return nums;
