public int[] zeroMax(int[] nums) {
    int maxOdd = -1;
    for (int i = nums.length - 1; i >= 0; i--) {
        if (nums[i] % 2 != 0) {
            maxOdd = nums[i];
        }
        if (nums[i] == 0) {
            nums[i] = maxOdd;
        }
    }
    return nums;
}

