Code:
public int countClumps(int[] nums) {
    if (nums == null || nums.length == 0) return 0;

    int count = 0;
    int i = 0;

    while (i < nums.length) {
        if (i > 0 && nums[i] == nums[i - 1]) {
            i++;
        } else {
            int j = i;
            while (j < nums.length && nums[j] == nums[i]) j++;

            count++;
            i = j;
        }
    }

    return count;
}

