public int[] shiftLeft(int[] nums) {
    if(nums.length < 1)
        return nums;

    int temp = nums[0];
    for(int i = 0; i < nums.length - 1; i++){
        nums[i] = nums[i+1];
    }
    nums[nums.length-1] = temp;
    return nums;
}

public int[] shiftLeft(int[] nums) {
    int N = nums.length;
    if (N == 0 || N == 1) return nums;
    int temp = nums[0];
    for (int i = 0; i < N - 1; i++) {
        nums[i] = nums[i + 1];
    }
    nums[N - 1] = temp;
    return nums;
}

